enum SFXOverflowPolicy {
	## 跳过新的 SFX 请求。
	SKIP_NEW,
	## 停止最早播放的 SFX，并播放新的请求。
	STOP_OLDEST,
}

enum ParallelPolicy {
	## 所有子节点成功才成功，任意子节点失败即失败。
	REQUIRE_ALL,
	## 任意子节点成功即成功，所有子节点失败才失败。
	REQUIRE_ONE,
}

enum Lifetime {
	## 首次解析后缓存实例，后续解析复用。
	SINGLETON,
	## 每次解析都重新创建实例。
	TRANSIENT,
}

enum DependencyRemovalPolicy {
	## 保留依赖能力，适合依赖能力需要在主能力移除后继续存在的场景。
	KEEP_DEPENDENCIES,
	## 移除仅由当前能力自动补齐且未被显式添加的依赖能力。
	REMOVE_AUTO_DEPENDENCIES,
}

enum UpdateMode {
	## patch 记录整体替换 base 记录。
	REPLACE_RECORD,
	## patch 记录与 base 记录按字段合并，嵌套 Dictionary 递归合并。
	MERGE_FIELDS,
}

enum IssueSeverity {
	## 警告，不阻止报告通过。
	WARNING,
	## 错误，会让报告失败。
	ERROR,
}

enum Direction {
	## 输入端口。
	INPUT,
	## 输出端口。
	OUTPUT,
}

enum TargetType {
	## 目标是本地玩家索引，通过 GFInputDeviceUtility 解析到手柄设备。
	PLAYER,
	## 目标是 Godot 手柄设备 ID。
	DEVICE,
}

enum OverflowPolicy {
	## 跳过新的播放请求。
	SKIP_NEW,
	## 停止最早的播放实例。
	STOP_OLDEST,
}

enum HexOrientation {
	## 尖顶朝上。
	POINTY_TOP,
	## 平顶朝上。
	FLAT_TOP,
}

enum LoopCatchUpPolicy {
	## 保留剩余时间，在后续 tick 继续逐事件处理。
	DEFER_EXCESS,
	## 跳过超预算的完整周期，只重建最终周期状态。
	SKIP_EXCESS_CYCLES,
}

enum AllowedSign {
	## 只保留大于等于 0 的值。
	POSITIVE,
	## 只保留小于等于 0 的值。
	NEGATIVE,
}

enum Format {
	## Godot Variant 二进制编码。
	BINARY,
	## UTF-8 JSON 编码。
	JSON,
}

enum ScopeMode {
	## 直接复用最近的父级上下文架构；若不存在则回退到全局 Gf 架构。
	INHERITED,
	## 创建新的局部架构，并将最近的父级或全局架构作为依赖回退来源。
	SCOPED,
}

enum StackExitPolicy {
	## 每个暂停状态都必须通过 can_exit()。
	REQUIRE_GUARDS,
	## 显式绕过暂停状态的 can_exit()，用于 teardown 等强制恢复场景。
	FORCE,
}

enum TouchMode {
	## 只加载资源并触碰 RID。
	RID_ONLY,
	## 使用离屏临时渲染节点让材质或 Mesh 参与一次渲染。
	TEMPORARY_RENDER_NODES,
}

enum RestorePolicy {
	## 只把数据应用到已存在的 Source。
	APPLY_ONLY_EXISTING,
	## 允许 GFSaveGraphUtility 使用注册的工厂补建实体。
	ALLOW_FACTORIES,
}

enum OverflowPolicy {
	## 跳过新的播放请求。
	SKIP_NEW,
	## 停止最早的播放实例。
	STOP_OLDEST,
}

enum CompositionMode {
	## 按权重混合所有行为。
	BLEND,
	## 选择第一个超过阈值的行为。
	PRIORITY,
}

enum Format {
	## 稳定排序后的 JSON 文本。
	JSON,
	## Godot Variant 二进制格式。
	BINARY,
}

enum Operation {
	## 压入当前层级栈顶。
	PUSH,
	## 替换当前层级栈。
	REPLACE,
}

enum PanelMode {
	## 普通面板。
	NORMAL,
	## Modal 面板，通常会独占当前交互焦点。
	MODAL,
}

enum ParallelCompletionPolicy {
	## 等待所有需要等待的子动作完成。
	WAIT_FOR_ALL,
	## 任一子动作完成后就结束动作组。
	FIRST_COMPLETED,
}
